import{_ as t,c as a,a1 as i,o}from"./chunks/framework.BDxlaA_J.js";const p=JSON.parse('{"title":"Hiding Data using Steganography","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/5-system-hacking/9-Steganography.md","filePath":"categories/ethical-hacking-labs/5-system-hacking/9-Steganography.md"}'),n={name:"categories/ethical-hacking-labs/5-system-hacking/9-Steganography.md"};function s(r,e,c,g,d,l){return o(),a("div",null,e[0]||(e[0]=[i('<h1 id="hiding-data-using-steganography" tabindex="-1">Hiding Data using Steganography <a class="header-anchor" href="#hiding-data-using-steganography" aria-label="Permalink to &quot;Hiding Data using Steganography&quot;">​</a></h1><p>Steganography is the practice of concealing a file, message, image, or video within another file, message, image, or video.</p><p>Network steganography describes all the methods used for transmitting data over a network without it being detected. Several methods for hiding data in a network have been proposed, but the main drawback of most of them is that they do not offer a secondary layer of protection. If steganography to transfer sensitive information out of the target system undetected.</p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>Use Steganography in Windows and Linux.</li><li>Using Snow steganography to hide files and data.</li><li>Hiding files using spaces and tabs.</li><li>Hide secret text messages in images using OpenStego.</li></ul><h2 id="hiding-data-using-snow-windows" tabindex="-1">Hiding Data using Snow (Windows) <a class="header-anchor" href="#hiding-data-using-snow-windows" aria-label="Permalink to &quot;Hiding Data using Snow (Windows)&quot;">​</a></h2><p>Snow website: <a href="http://darkside.com.au/snow/index.html" target="_blank" rel="noreferrer">http://darkside.com.au/snow/index.html</a></p><p>Snow is used to conceal messages in ASCII test by appending whitespace to the end of the lines. Because spaces and tabs are generally not visible in text viewers, the message is effectively hidden from casual observers. Anf if the built-in encryption is used, the message cannot be read even if it is detected.</p><p>Snow exploits the steganographic nature of whitespace. Locating trailing whitespace in text is like finding a polar bear in a snow storm, it uses the ICE encryption algorithm, so the name is thematically consistent.</p><p><strong>ICE encryption</strong>: This encryption algorithm is a 64-bit block cipher. It runs in 1-bit cipher-feedback (CFB) mode, which although inefficient (requiring a full 64-bit encryption for each bit of output).</p><ol><li><p>Launch the <strong>command prompt</strong> and navigate to the Snow folder. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1e1e57a1a30bab7ad94f502b3bba5107098448c0/snow-01.png" alt="snow-01"></p></li><li><p>Create a readme.txt <strong>inside the SNOW folder</strong> with a random message like: <code>hello world!</code></p></li><li><p>Now go back to the <strong>command prompt</strong> and create a secret information <code>snow -C -m &quot;My sketchy wallet: 3FkenCiXpSLqD8L79intRNXUgjRoH9sjXy&quot; -p &quot;pa55&quot; readme.txt readme2.txt</code></p></li></ol><p><code>-m &quot;message&quot;</code>: the secret string <code>pa55</code>: is the password, you can type any password you like. <code>readme2.txt</code>: is the name of another file which will be created automatically in the same location.</p><p>Now the data (<code>&quot;My sketchy wallet: 3FkenCiXpSLqD8L79intRNXUgjRoH9sjXy&quot;</code>) is hidden inside the <strong>readme2.txt</strong> file with the contents of the <strong>readme.txt</strong>.</p><p><em>readme2.txt = readme.txt + &quot;My sketchy wallet: 3FkenCiXpSLqD8L79intRNXUgjRoH9sjXy&quot;</em></p><p><strong>You can open both readme.txt and readme2.txt to check if there&#39;s any divergences</strong>, besides the whitespaces as shown below:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1e1e57a1a30bab7ad94f502b3bba5107098448c0/snow-whitespaces-02.png" alt="whitespaces-difference"></p><ol start="4"><li>To reveal the hidden contents, type: <code>snow -C -p &quot;pa55&quot; readme2.txt</code><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/346be861372d685fe81d0a7dd3d9cb7687c2592a/snow-03.png" alt="snow3"></li></ol><hr><h1 id="image-steganography-using-openstego-windows" tabindex="-1">Image Steganography using OpenStego (Windows) <a class="header-anchor" href="#image-steganography-using-openstego-windows" aria-label="Permalink to &quot;Image Steganography using OpenStego (Windows)&quot;">​</a></h1><p>OpenStego is a steganography tool that hides data inside images. OpenStego is a Java-based application and supports password-based encryption of data for additional layer of security. It uses DES algorithm for data encryption, in conjunction with MDS hashing to derive the DES key from the password provided.</p><p>OpenStego website: <a href="https://www.openstego.com/" target="_blank" rel="noreferrer">https://www.openstego.com/</a></p><ol><li><p>Install the OpenStego and Open the application <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/2a94c49858a92a09855df3edab939b2d731b8b8f/openstego-1.png" alt="OpenStego-1"></p></li><li><p>Click on <strong>ellipsis button</strong> on <strong>Message File</strong> input and select the text file that contains on the OpenStego folder (This text file contains &#39;dummy&#39; sensitive information such as VISA and pin numbers). <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/3ece1184799bc34f54c0523fa8c0b6bd6efe9f30/openstego-2.png" alt="OpenSTego-2"></p></li><li><p>Next, click on the second <strong>ellipsis button</strong> (<strong>Cover File</strong>) and select <strong>Island.jpg</strong> that also inside the OpenStego folder. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/ef22f60c5f3883f11031c0e2c3e18835e246c578/openStego-3.png" alt="OpenStego-3"></p></li><li><p>Click on the third <strong>ellipsis button</strong> <strong>(Output Stego File)</strong>, select the <strong>Desktop</strong> and provide the file name <strong>stego</strong>.</p></li><li><p>Now, click <strong>Hide Data</strong> on the right lower corner. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6bcf0fc1ad730e4b8bfb0f29695cd3d5da026db4/openStego-5.png" alt="OpenStego-5"></p></li></ol><p>Open the image file on your desktop, you will see only the image but not the contents of the message(text file) embedded in it, as shown below:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/8265b66f9795426b604a8b602df5027d27a69897/stego-6.png" alt="OpenStego-6"></p><h3 id="obtain-the-text-file-from-the-image" tabindex="-1">Obtain the Text file from the Image <a class="header-anchor" href="#obtain-the-text-file-from-the-image" aria-label="Permalink to &quot;Obtain the Text file from the Image&quot;">​</a></h3><ol><li><p>Go back to the OpenStego window and click the <strong>Extract Data</strong> button on the left corner.</p></li><li><p>Click on the first <strong>ellipsis button</strong> <strong>(Input Stego File)</strong>, select the image that you generated from <strong>Desktop</strong> and your <strong>Output Folder</strong> on the next ellipsis button. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/80722e31e7a359444d428f12b87bf31d64cfb739/openstego-7.png" alt="openstego7"></p></li><li><p>Click <strong>Extract Data</strong> on the right lower corner. This will extract the message file from the image.</p></li><li><p>The file displays all the information contained in the document, as show below: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/80722e31e7a359444d428f12b87bf31d64cfb739/openstego-8.png" alt="openstego8"></p></li></ol><hr><h1 id="using-quick-stego-windows" tabindex="-1">Using Quick Stego (Windows) <a class="header-anchor" href="#using-quick-stego-windows" aria-label="Permalink to &quot;Using Quick Stego (Windows)&quot;">​</a></h1><p>Quick Stego hides text in pictures so that only other users of Quick Stego can retrieve and read the hidden secret messages.</p><p>QuickStego website: <a href="http://quickcrypto.com/free-steganography-software.html" target="_blank" rel="noreferrer">http://quickcrypto.com/free-steganography-software.html</a></p><h3 id="hide-the-text-inside-the-image" tabindex="-1">Hide the text inside the image <a class="header-anchor" href="#hide-the-text-inside-the-image" aria-label="Permalink to &quot;Hide the text inside the image&quot;">​</a></h3><ol><li><p>Install the Quick Stego.</p></li><li><p>Launch the Application. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b3a67a059d4adeff6da89ec1b797b4ee7aa3c1c3/Quickstego-0.png" alt="QuickStego-0"></p></li><li><p>Click on <strong>Open Image</strong>, under Picture, Image, Photo File.</p></li><li><p>Select the image inside the <strong>QuickStego folder</strong>. <code>02_nissan_gt-r_specv_opt.jpg</code></p></li><li><p>Next, click on <strong>Open Text</strong> under Text File, as shown below: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/48ad0711987d02ced80915853bf83f9650ae5d18/QuickStego-1.png" alt="QuickStego-1"></p></li><li><p>Select the <strong>text file.txt</strong> inside the <strong>QuickStego folder</strong>.</p></li><li><p>The selected text will be added in the text box right next to the image, as show below <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b3a67a059d4adeff6da89ec1b797b4ee7aa3c1c3/quickStego-2.png" alt="QuickStego-2"></p></li><li><p>Click on <strong>Hide Text</strong> under Steganography <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b3a67a059d4adeff6da89ec1b797b4ee7aa3c1c3/quickstego-3.png" alt="QuickStego-3"></p></li><li><p>To save the image file (in which the text is hidden), Click on <strong>Save Image</strong>, under Picture, Image, Photo File.</p></li></ol><p>The file is now saved as &quot;stego&quot;. Though it seems to be a normal image file, it has the text hidden in it, <strong>which can be visible by viewing it in Quick Stego.</strong></p><hr><h1 id="hiding-data-using-steghide-kali-linux" tabindex="-1">Hiding Data using Steghide (Kali Linux) <a class="header-anchor" href="#hiding-data-using-steghide-kali-linux" aria-label="Permalink to &quot;Hiding Data using Steghide (Kali Linux)&quot;">​</a></h1><p>Steghide is a steganography program that is able to hide data in various kinds of image- and audio-files. The color- respectivly sample-frequencies are not changed thus making the embedding resistant against first-order statistical tests.</p><p>Official repository: <a href="https://github.com/StefanoDeVuono/steghide" target="_blank" rel="noreferrer">https://github.com/StefanoDeVuono/steghide</a></p><p>Installing Steghide is very simple in Kali Linux, because is already available in Kali Linux repository.</p><p>Run the following command:</p><p><code>sudo apt-get update</code><code>sudo apt-get install steghide</code></p><h3 id="hide-text-in-image-file" tabindex="-1">Hide Text in Image file <a class="header-anchor" href="#hide-text-in-image-file" aria-label="Permalink to &quot;Hide Text in Image file&quot;">​</a></h3><ol><li><p>Create a folder on your Desktop with an <strong>image file</strong> and a <strong>secret text file</strong>. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/fdcd09b49b5f46b4e9c23ae266b41feadd1e7ce8/steg-kali-0.png" alt="Kali-Steg-Files-0"></p></li><li><p>To hide the text in image, navigate to the /Desktop/steg/ folder and type: <code>steghide embed -cf black-cat.jpg -ef secret-text.txt</code><code>-cf</code>: Cover file &lt; filename &gt; <code>-ef</code>: Embedded File &lt; filename &gt; <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c05066032cd10aa55749c47426d139d6abd14e09/Steg-Kali-1.png" alt="Steg-Kali-command"> This command will embed the file secret-text.txt in the cover file black-cat.jpg protected with a passphrase.</p></li></ol><h3 id="extract-text-from-the-image-file" tabindex="-1">Extract text from the Image file <a class="header-anchor" href="#extract-text-from-the-image-file" aria-label="Permalink to &quot;Extract text from the Image file&quot;">​</a></h3><p>After you have embedded your secret data, the receiver has to use steghide in the following way:</p><ol><li>Extract the Data <code>steghide extract -sf black-cat.jpg </code><code>-sf</code>: Stego file</li><li>Enter the correct passphrase. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/bcbab9ca9f66ea7785cab8e15fc52d5492b0ea2e/KaliStego-3.png" alt="KaliStego-2"> The contents of the original file secret-text.txt will be extracted from the stego file black-cat.jpg and saved in the current directory.</li></ol><h3 id="view-information-of-embedded-data" tabindex="-1">View Information of Embedded Data <a class="header-anchor" href="#view-information-of-embedded-data" aria-label="Permalink to &quot;View Information of Embedded Data&quot;">​</a></h3><p>If some file contains embedded data and you want to get some information about it before extracting it, type the command:</p><p><code>steghide info black-cat.jpg</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c0fc9841d6bd1d58adbea07cd0b71466cc7bf151/steg-kali-4-embedded.png" alt="Embedded Data"></p><p>Steghide will then try to extract the embedded data with that passphrase and – if it succeeds – print some information about it.</p><hr><h3 id="honorable-mention" tabindex="-1">Honorable Mention <a class="header-anchor" href="#honorable-mention" aria-label="Permalink to &quot;Honorable Mention&quot;">​</a></h3><p>StegoSuite for Linux and Windows is a free and open source steganography tool written in Java.</p><p><a href="https://stegosuite.org/" target="_blank" rel="noreferrer">https://stegosuite.org/</a></p>',54)]))}const m=t(n,[["render",s]]);export{p as __pageData,m as default};
